#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        long long N, K;
        scanf("%lld %lld", &N, &K);
        double prob = 1.0 / N;
        if (K > 0) {
            prob = 1.0 / (N / (1LL << K));
        }
        printf("%.6f\n", prob);
    }
    return 0;
}

