import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            long N = sc.nextLong();
            long K = sc.nextLong();
            double prob = 1.0 / N;
            if (K > 0) {
                prob = 1.0 / (N / (1L << K));
            }
            System.out.printf("%.6f\n", prob);
        }
    }
}

